function renderVerkosto(t,e,o){const i=t.verkosto[e];if(!i)return;const n=t.entities;let a=`\n        <div class="verkosto-header" style="text-align: center; margin-bottom: 2rem;">\n            <h2 style="color: #0a2540; margin-bottom: 0.5rem;">🧠 Palveluverkoston suositukset: ${i.otsikko}</h2>\n            <p style="color: #4a5568;">Saattaisit olla kiinnostunut myös näistä paikallisista toimijoista ja mahdollisuuksista.</p>\n        </div>\n        <div class="verkosto-grid" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem;">\n    `;i.yritykset&&i.yritykset.length>0&&(a+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #0056b3; margin-bottom: 1rem; font-size: 1.2rem;">🏢 Yritykset</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',i.yritykset.forEach(t=>{const e=n[t];e&&(a+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${e.nimi}</strong><br><small style="color: #666;">${e.kuvaus}</small></li>`)}),a+="</ul></div>"),i.tarjoan_apua&&i.tarjoan_apua.length>0&&(a+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #28a745; margin-bottom: 1rem; font-size: 1.2rem;">🤝 Tarjoaa apua</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',i.tarjoan_apua.forEach(t=>{const e=n[t];e&&(a+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${e.otsikko}</strong></li>`)}),a+="</ul></div>"),i.harrastukset&&i.harrastukset.length>0&&(a+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #ffc107; margin-bottom: 1rem; font-size: 1.2rem;">👥 Harrastusryhmät</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',i.harrastukset.forEach(t=>{const e=n[t];e&&(a+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${e.otsikko}</strong><br><small style="color: #666;">Kiinnostuneita: ${e.kiinnostuneet||0}</small></li>`)}),a+="</ul></div>"),i.projektit&&i.projektit.length>0&&(a+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #dc3545; margin-bottom: 1rem; font-size: 1.2rem;">🚀 Projektit</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',i.projektit.forEach(t=>{const e=n[t];e&&(a+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${e.otsikko}</strong></li>`)}),a+="</ul></div>"),a+="</div>",a+='<div style="text-align: center; margin-top: 2rem;">\n        <p style="color: #666; font-size: 0.9rem; margin-bottom: 0.5rem;">Kokeile muita suositusteemoja:</p>\n        <div style="display: flex; justify-content: center; gap: 0.5rem; flex-wrap: wrap;">',t.kaikki_tagit&&Object.keys(t.kaikki_tagit).forEach(o=>{a+=`<button onclick="renderVerkostoData('${o}')" style="background: ${o===e?"#0056b3":"#e2e8f0"}; color: ${o===e?"white":"#333"}; border: none; padding: 0.5rem 1rem; border-radius: 20px; cursor: pointer; font-family: inherit;">${t.kaikki_tagit[o].otsikko}</button>`}),a+="</div></div>",o.innerHTML=a}function renderSanapilvi(){const t=document.getElementById("sanapilvi-tags"),e=document.getElementById("sanapilvi-container");t&&e&&fetch("https://mediazoo.fi/laukaainfo-web/ilmoitukset-api.php?action=list").then(t=>t.json()).then(o=>{if("success"===o.status&&o.sanapilvi){const i=o.sanapilvi,n=Object.keys(i);if(n.length>0){e.style.display="block";let o="";const a={tietokoneet:"💻",piha:"🌳",rakentaminen:"🔨",kuljetus:"🚗",seniorit:"👵",tapahtumat:"🎉",musiikki:"🎵",muu:"📌",digitaaliset:"💻",kodinhoito:"🏠",piha_puutarha:"🌳",rakentaminen_remontointi:"🛠",liikenne:"🚗",seniorit:"👵",lapset:"👶",oppiminen:"📚",musiikki_wizard:"🎵",valokuvaus:"📷",liikunta:"🏃",luonto:"🌱",yhdistys:"🤝",yrittajyys:"💼"};n.forEach(t=>{const e=i[t],n=a[t]||"📌",r=Math.min(1.5,.9+.1*e);o+=`<button onclick="renderVerkostoData('${t}')"\n                            style="background: #e2e8f0; border: none; padding: 0.4rem 0.8rem; border-radius: 20px;\n                            cursor: pointer; font-size: ${r}rem; transition: background 0.2s; font-family: inherit;">\n                            ${n} ${function(t){return t.replace(/_/g," ").replace(/\b\w/g,t=>t.toUpperCase())}(t)} <span style="opacity: 0.6; font-size: 0.8em;">(${e})</span>\n                        </button>`}),t.innerHTML=o}}}).catch(t=>console.error("Virhe sanapilven latauksessa:",t))}document.addEventListener("DOMContentLoaded",()=>{if(!document.getElementById("palveluverkosto-suositukset"))return;const t=["tietokoneet","rakentaminen","musiikki"],e=t[Math.floor(Math.random()*t.length)];renderVerkostoData(e)}),window.renderVerkostoData=function(t){const e="https://mediazoo.fi/laukaainfo-web/suosittelija.php?tag="+encodeURIComponent(t);fetch(e).then(t=>t.json()).then(e=>{if("success"===e.status){const o=document.getElementById("palveluverkosto-suositukset");renderVerkosto(e,t,o)}else console.error("API palautti virheen:",e.message)}).catch(t=>console.error("Virhe ladattaessa palveluverkoston dataa:",t))},document.addEventListener("DOMContentLoaded",renderSanapilvi);